def mysql_escape_string_literal(s: str) -> str:
    return s.replace("\\", "\\\\").replace("'", "\\'")


def build_load_sql(args, file_path: str) -> str:
    infile_kw = "LOCAL INFILE" if args.local else "INFILE"
    modifiers = []
    if args.replace:
        modifiers.append("REPLACE")
    if args.ignore:
        modifiers.append("IGNORE")
    modifiers_sql = (" " + " ".join(modifiers)) if modifiers else ""

    fp = mysql_escape_string_literal(file_path)

    parts = []
    parts.append(f"LOAD DATA{modifiers_sql} {infile_kw} '{fp}'")
    parts.append(f"INTO TABLE `{args.table}`")
    parts.append(f"CHARACTER SET {args.charset}")

    fields = []
    if args.fields_terminated_by is not None:
        fields.append(f"TERMINATED BY '{mysql_escape_string_literal(args.fields_terminated_by)}'")
    if args.fields_enclosed_by:
        fields.append(f"ENCLOSED BY '{mysql_escape_string_literal(args.fields_enclosed_by)}'")
    if args.fields_escaped_by is not None:
        fields.append(f"ESCAPED BY '{mysql_escape_string_literal(args.fields_escaped_by)}'")
    if fields:
        parts.append("FIELDS " + " ".join(fields))

    if args.lines_terminated_by is not None:
        parts.append(f"LINES TERMINATED BY '{mysql_escape_string_literal(args.lines_terminated_by)}'")

    if args.ignore_lines and args.ignore_lines > 0:
        parts.append(f"IGNORE {args.ignore_lines} LINES")

    if args.columns:
        cols = [c.strip() for c in args.columns.split(",") if c.strip()]
        if cols:
            parts.append("(" + ", ".join(f"`{c}`" if not c.startswith("@") else c for c in cols) + ")")

    if args.set_clause:
        parts.append("SET " + args.set_clause)

    return "\n".join(parts) + ";"


def connect_mysql(args):
    password = args.password
    if password is None:
        password = getpass.getpass("MySQL password: ")

    conn = mysql.connector.connect(
        host=args.host,
        port=args.port,
        user=args.user,
        password=password,
        database=args.database,
        allow_local_infile=True,
        autocommit=False,
    )
    return conn


def iter_input_files(initial_files):
    files = list(initial_files or [])
    if files:
        for f in files:
            yield f
        return

    while True:
        try:
            s = input("Enter file path to import (blank to finish): ").strip()
        except EOFError:
            break
        if not s:
            break
        yield s


def normalize_file_path(p: str) -> str:
    pp = Path(p).expanduser()
    try:
        pp = pp.resolve()
    except Exception:
        pp = Path(os.path.abspath(str(pp)))
    return str(pp)


def main():
    args = parse_args()

    if not args.database:
        print("Error: --database is required (or set MYSQL_DATABASE).", file=sys.stderr)
        sys.exit(2)

    conn = connect_mysql(args)
    cur = conn.cursor()

    try:
        cur.execute("SET SESSION local_infile = 1;")
    except Exception:
        pass

    imported = 0
    for fp in iter_input_files(args.files):
        fp = normalize_file_path(fp)
        if not os.path.exists(fp):
            print(f"Skipping (not found): {fp}", file=sys.stderr)
            continue

        sql = build_load_sql(args, fp)

        if args.dry_run:
            print(sql)
            continue

        try:
            cur.execute(sql)
            conn.commit()
            imported += 1
            try:
                print(f"Imported: {fp} (rows affected: {cur.rowcount})")
            except Exception:
                print(f"Imported: {fp}")
        except mysql.connector.Error as e:
            conn.rollback()
            print(f"Failed: {fp}", file=sys.stderr)
            print(f"MySQL error: {e}", file=sys.stderr)

    cur.close()
    conn.close()

    if args.dry_run:
        return
    print(f"Done. Files imported: {imported}")


if __name__ == "__main__":
    main()